**MongoDB Transactions:**

Transactions ensure multiple operations either all succeed or all fail together (atomicity). They're essential when multiple collections must be updated consistently.

**Example: Order Creation Transaction:**

```javascript
const mongoose = require('mongoose');
const Order = require('../models/Order');
const Product = require('../models/Product');
const User = require('../models/User');
const asyncHandler = require('../utils/asyncHandler');
const AppError = require('../utils/AppError');

exports.createOrder = asyncHandler(async (req, res, next) => {
  const { items, shippingAddress } = req.body;

  // Start transaction
  const session = await mongoose.startSession();
  session.startTransaction();

  try {
    let totalAmount = 0;
    const orderItems = [];

    // 1. Validate products and calculate total
    for (const item of items) {
      const product = await Product.findById(item.productId).session(session);

      if (!product) {
        throw new AppError(`Product not found: ${item.productId}`, 404);
      }

      if (product.stock < item.quantity) {
        throw new AppError(
          `Insufficient stock for ${product.name}`, 
          400
        );
      }

      // Update stock
      product.stock -= item.quantity;
      await product.save({ session });

      // Add to order items
      orderItems.push({
        product: product._id,
        name: product.name,
        price: product.price,
        quantity: item.quantity
      });

      totalAmount += product.price * item.quantity;
    }

    // 2. Create order
    const [order] = await Order.create([{
      user: req.user._id,
      items: orderItems,
      totalAmount,
      shippingAddress,
      status: 'pending'
    }], { session });

    // 3. Update user's order history
    await User.findByIdAndUpdate(
      req.user._id,
      { 
        $push: { orders: order._id },
        $inc: { totalSpent: totalAmount }
      },
      { session }
    );

    // Commit transaction
    await session.commitTransaction();

    res.status(201).json({
      success: true,
      data: order
    });

  } catch (error) {
    // Rollback on any error
    await session.abortTransaction();
    return next(error);
  } finally {
    session.endSession();
  }
});
```

**Key Points:**
- All operations use same `session`
- If any operation fails, all are rolled back
- `session.commitTransaction()` makes changes permanent
- `session.abortTransaction()` undoes all changes

**Indexing Strategies:**

1. **Single Field Index:** For queries filtering on one field
2. **Compound Index:** For queries filtering/sorting on multiple fields
3. **Text Index:** For full-text search
4. **Partial Index:** Index only documents matching a condition
5. **TTL Index:** Auto-delete documents after time

**Product Model with Optimized Indexes:**

```javascript
const productSchema = new mongoose.Schema({
  name: String,
  slug: { type: String, unique: true },
  description: String,
  price: Number,
  category: String,
  brand: String,
  tags: [String],
  ratings: {
    average: Number,
    count: Number
  },
  stock: Number,
  isActive: { type: Boolean, default: true },
  createdAt: { type: Date, default: Date.now }
});

// 1. Unique slug lookup
productSchema.index({ slug: 1 }, { unique: true });

// 2. Category browsing with price sort
// Supports: find({ category: 'x' }).sort({ price: 1 })
productSchema.index({ category: 1, price: 1 });

// 3. Category browsing with rating sort
// Supports: find({ category: 'x' }).sort({ 'ratings.average': -1 })
productSchema.index({ category: 1, 'ratings.average': -1 });

// 4. Full-text search with weighted fields
productSchema.index(
  { name: 'text', description: 'text', tags: 'text' },
  { weights: { name: 10, tags: 5, description: 1 } }
);

// 5. Active products by category (partial index)
productSchema.index(
  { category: 1, createdAt: -1 },
  { partialFilterExpression: { isActive: true } }
);

// 6. Tag filtering (multikey index)
productSchema.index({ tags: 1 });

// 7. Price range queries
productSchema.index({ price: 1 });

// 8. Brand filtering with price
productSchema.index({ brand: 1, price: 1 });
```

**Index Design Rules:**

1. **Equality → Sort → Range:**
```javascript
// Query: find({ category: 'x', price: { $gte: 100 } }).sort({ name: 1 })
// Index: { category: 1, name: 1, price: 1 }
```

2. **Most selective field first:**
```javascript
// If brand has more unique values than category
// Index: { brand: 1, category: 1 }
```

3. **Cover the query if possible:**
```javascript
// Query only needs name and price
// Index: { category: 1, name: 1, price: 1 }
// This index can return results without reading documents
```

